CREATE VIEW `ads_short_video_account_like_view` (`id` COMMENT "点赞表主键id", `account_id` COMMENT "用户id", `epis_id` COMMENT "集数id", `create_time` COMMENT "创建时间", `is_delete` COMMENT "逻辑删除字段", `region_id` COMMENT "归属区域 id，1：香港，2：北美；", `series_id` COMMENT "剧id", `sr_createtime` COMMENT "starrocks数据注入时间", `sr_updatetime` COMMENT "starrocks数据更新时间")
COMMENT "海外短剧-用户点赞表" AS SELECT `ods`.`ods_tidb_short_video_account_like`.`id`, `ods`.`ods_tidb_short_video_account_like`.`accountid` AS `account_id`, `ods`.`ods_tidb_short_video_account_like`.`episid` AS `epis_id`, `ods`.`ods_tidb_short_video_account_like`.`createtime` AS `create_time`, `ods`.`ods_tidb_short_video_account_like`.`isdelete` AS `is_delete`, `ods`.`ods_tidb_short_video_account_like`.`regionid` AS `region_id`, `ods`.`ods_tidb_short_video_account_like`.`seriesid` AS `series_id`, `ods`.`ods_tidb_short_video_account_like`.`sr_createtime`, `ods`.`ods_tidb_short_video_account_like`.`sr_updatetime`
FROM `ods`.`ods_tidb_short_video_account_like`;